// // This module implements a 16-bit DRAM cell with write and read functionalities. However, it does not store or retrieve data as intended.
module dram_cell (  
    input wire [15:0] data_in,  
    input wire we,  
    input wire re,  
    output reg [15:0] data_out  
);  
    reg [15:0] memory;  

    always @(posedge we) begin  
        memory <= data_in;  
    end  

    always @(posedge re) begin  
        data_out <= memory;  
    end  
endmodule
